// The station's memory — every spin, appended once, forever counted.
// Lives in workflow static data: no credentials, no database.
const sd = $getWorkflowStaticData('global');
sd.days = sd.days || {};
sd.all = sd.all || {};
const np = $input.first().json || {};
const song = np.now_playing && np.now_playing.song;
if (!song || !song.title) { return [{ json: { logged: false, why: 'no song' } }]; }
const ti = String(song.title).trim().slice(0, 140);
const ar = String(song.artist || '').trim().slice(0, 140);
if (!ti || ti.toLowerCase() === 'mellow mountain radio') { return [{ json: { logged: false, why: 'station id' } }]; }
const key = (ti + '|' + ar).toLowerCase();
if (sd.lastKey === key) { return [{ json: { logged: false, why: 'same song' } }]; }
sd.lastKey = key;
const now = new Date();
const phx = new Date(now.toLocaleString('en-US', { timeZone: 'America/Phoenix' }));
const d = phx.getFullYear() + '-' + String(phx.getMonth() + 1).padStart(2, '0') + '-' + String(phx.getDate()).padStart(2, '0');
const t = String(phx.getHours()).padStart(2, '0') + ':' + String(phx.getMinutes()).padStart(2, '0');
const art = song.art && String(song.art).indexOf('http') === 0 ? String(song.art).slice(0, 300) : '';
sd.days[d] = sd.days[d] || [];
sd.days[d].push({ t, ti, ar, art });
if (sd.days[d].length > 600) sd.days[d] = sd.days[d].slice(-600);
const iso = now.toISOString();
const rec = sd.all[key] || { ti, ar, n: 0, first: iso };
rec.n++; rec.last = iso; if (art) rec.art = art;
sd.all[key] = rec;
if (!sd.since) sd.since = d;
// keep 90 days of day-logs; the all-time tallies stay forever
const keys = Object.keys(sd.days).sort();
while (keys.length > 90) { delete sd.days[keys.shift()]; }
return [{ json: { logged: true, d, t, ti, ar } }];

// Which day does the site want? Query a day either side so Phoenix's
// evening (UTC's next morning) is never dropped at the boundary.
const q = $input.first().json.query || {};
const phx = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Phoenix' }));
const f = (x) => x.getFullYear() + '-' + String(x.getMonth() + 1).padStart(2, '0') + '-' + String(x.getDate()).padStart(2, '0');
const today = f(phx);
let day = String(q.d || today);
if (!/^\d{4}-\d{2}-\d{2}$/.test(day)) day = today;
const next = new Date(day + 'T12:00:00Z'); next.setUTCDate(next.getUTCDate() + 1);
const prev = new Date(day + 'T12:00:00Z'); prev.setUTCDate(prev.getUTCDate() - 1);
return [{ json: { day, today, start: f(prev), end: f(next) } }];

// The chart week: the last 7 days, straight from the station's records.
const phx = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Phoenix' }));
const f = (x) => x.getFullYear() + '-' + String(x.getMonth() + 1).padStart(2, '0') + '-' + String(x.getDate()).padStart(2, '0');
const end = new Date(phx); end.setDate(end.getDate() + 1);
const start = new Date(phx); start.setDate(start.getDate() - 7);
return [{ json: { start: f(start), end: f(end) } }];

// Sweep 400 days of AzuraCast's own song history in 10-day chunks —
// the records run back over a year; take all of it for the lifetime index.
const out = [];
const day = 86400000;
const now = Date.now();
for (let back = 400; back > 0; back -= 10) {
  const s = new Date(now - back * day), e = new Date(now - Math.max(0, back - 10) * day);
  const f = (x) => x.toISOString().slice(0, 10);
  out.push({ json: { start: f(s), end: f(e) } });
}
return out;

// Build the lifetime index from the whole sweep: spin counts and TRUE
// first-play dates for every song the station has records of.
const sd = $getWorkflowStaticData('global');
sd.all = sd.all || {};
if (sd.backfillDone) {
  return [{ json: { note: 'sweep already ran — counts preserved' } }];
}
const rows = [];
for (const item of $input.all()) {
  const j = item.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && j.played_at) rows.push(j);
  else if (j && Array.isArray(j.data)) rows.push(...j.data);
}
rows.sort((a, b) => (a.played_at || 0) - (b.played_at || 0));
let counted = 0;
for (const r of rows) {
  const song = r.song || {};
  const ti = String(song.title || '').trim().slice(0, 140);
  const ar = String(song.artist || '').trim().slice(0, 140);
  if (!ti || ti.toLowerCase() === 'mellow mountain radio' || !r.played_at) continue;
  const key = (ti + '|' + ar).toLowerCase();
  const ts = new Date(r.played_at * 1000);
  const iso = ts.toISOString();
  const phx = new Date(ts.toLocaleString('en-US', { timeZone: 'America/Phoenix' }));
  const dkey = phx.getFullYear() + '-' + String(phx.getMonth() + 1).padStart(2, '0') + '-' + String(phx.getDate()).padStart(2, '0');
  const rec = sd.all[key] || { ti, ar, n: 0, first: iso };
  rec.n++; counted++;
  if (iso < rec.first) rec.first = iso;
  if (!rec.last || iso > rec.last) rec.last = iso;
  const art = song.art && String(song.art).indexOf('http') === 0 ? String(song.art).slice(0, 300) : '';
  if (art) rec.art = art;
  sd.all[key] = rec;
  if (!sd.since || dkey < sd.since) sd.since = dkey;
}
sd.backfillDone = true;
return [{ json: { lifetimeCounted: counted, songsKnown: Object.keys(sd.all).length, since: sd.since || null } }];

// Shape the station's own records into the time machine's day view.
const sd = $getWorkflowStaticData('global');
const meta = $('Build the day range').first().json;
const rows = [];
for (const item of $input.all()) {
  const j = item.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && j.played_at) rows.push(j);
  else if (j && Array.isArray(j.data)) rows.push(...j.data);
}
const plays = [];
for (const r of rows) {
  const song = r.song || {};
  const ti = String(song.title || '').trim().slice(0, 140);
  const ar = String(song.artist || '').trim().slice(0, 140);
  if (!ti || ti.toLowerCase() === 'mellow mountain radio' || !r.played_at) continue;
  const phx = new Date(new Date(r.played_at * 1000).toLocaleString('en-US', { timeZone: 'America/Phoenix' }));
  const dkey = phx.getFullYear() + '-' + String(phx.getMonth() + 1).padStart(2, '0') + '-' + String(phx.getDate()).padStart(2, '0');
  if (dkey !== meta.day) continue;
  const t = String(phx.getHours()).padStart(2, '0') + ':' + String(phx.getMinutes()).padStart(2, '0');
  plays.push({ t, ti, ar });
}
plays.sort((a, b) => (a.t < b.t ? -1 : 1));
return [{ json: { ok: true, day: meta.day, today: meta.today, since: sd.since || null, plays } }];

// Spin charts from the station's own records — and only the MUSIC:
// the artist allowlist is the real MegaSeg library export, so spots,
// station IDs and news never chart. Never seeded, never padded.
const sd = $getWorkflowStaticData('global');
sd.all = sd.all || {};
const LIB = new Set(["10cc","ace","airplay","al green","al jarreau","al stewart","al wilson","alan parsons project","alive 'n kickin'","allman brothers band","ambrosia","america","andrew gold","anita baker","ann peebles","argent","atlanta rhythm section","band","beach boys","bee gees","bellamy brothers","bertie higgins","bill champlin, joseph williams & peter friestedt","bill withers","billy joel","billy ocean","billy preston","blondie","blue \u00f6yster cult","bob marley & the wailers","bob seger & the silver bullet band","bob welch","bobby caldwell","box tops","boz scaggs","bread","brothers johnson","bruce hornsby & the range","buffalo springfield","captain & tennille","carly simon","carpenters","champaign","cheryl lynn","chicago","chris norman & suzi quatro","christopher cross","chuck mangione","climax blues band","commodores","cream","creedence clearwater revival","crosby, stills & nash","crosby, stills, nash & young","daryl hall & john oates","dave mason","david mccallum","debarge","deele","deep purple","diana ross","dionne warwick","dire straits","dobie gray","dolly parton","don henley","donald fagen","donna summer","doobie brothers","doors","double","dr. hook","dr. john","dr. lonnie smith, george benson, joe lovano & ron carter","dramatics","dusty springfield","eagles","earth, wind & fire","eddie money","edgar winter group","edwin starr","electric light orchestra","elton john","elvin bishop","eric burdon & war","eye to eye","firefall","five man electrical band","fleetwood mac","floaters","foghat","foreigner","frankie beverly & maze","free","gap band","gary wright","george benson","george harrison","george michael","gerry rafferty","gino vannelli","glen campbell","glenn frey","gordon lightfoot","grand funk railroad","grateful dead","grover washington, jr.","guess who","harold melvin & the blue notes","harry nilsson","heatwave","herb alpert","herb alpert & the tijuana brass","herbie hancock","hiroshi suzuki","huey lewis & the news","intruders","isley brothers","j.j. cale","jackson browne","james gang","james ingram","james taylor","jay & the americans","jay ferguson","jefferson airplane","jennifer warnes","jim croce","jimi hendrix experience","jimmi hendrix","jimmy buffett","joe cocker","joe walsh","johnny cash","johnny nash","jones girls","journey","kansas","kenny loggins","kenny rogers","king harvest","kool & the gang","larsen-feiten band","led zeppelin","lee michaels","lee ritenour","leo sayer","leon haywood","leon ware","level 42","linda ronstadt","lionel richie","little river band","loggins & messina","lonnie liston smith & the cosmic echoes","looking glass","lou rawls","lovin' spoonful","luther vandross","lynyrd skynyrd","malo","manhattans","marshall tucker band","marty balin","matthew wilder","maxus","mccoys","michael jackson","michael martin murphey","michael mcdonald","mountain","mr. mister","mungo jerry","nicolette larson","norman greenbaum","o'jays","olivia newton-john","orleans","ozark mountain daredevils","pablo cruise","patrice rushen","paul davis","paul mccartney & wings","paul simon","pete townshend","peter cetera & amy grant","phil collins","philip bailey & phil collins","pilot","pink floyd","player","poco","prince","pure prairie league","quincy jones","reo speedwagon","rickie lee jones","robbie dupree","robert palmer","rod stewart","roy ayers ubiquity","rupert holmes","sade","sanford townsend band","seals & crofts","simply red","sly & the family stone","spinners","stampeders","starbuck","starland vocal band","stealers wheel","steely dan","steely dan & tom scott","steppenwolf","steve miller band","steve perry","stevie nicks","stevie nicks & don henley","stevie wonder","stevie woods","stylistics","sugarloaf","supertramp","temptations","three dog night","tina turner","todd rundgren","tom scott","tommy james","tommy james & the shondells","toto","traffic","traveling wilburys","utopia","van morrison","vicki lawrence","vince dicola","walter egan","war","warren zevon","waters","wings","young rascals","zombies","zz top & john lee hooker"]);
const norm = (s) => String(s || '').trim().toLowerCase().replace(/^the\s+/, '');
const isMusic = (ar) => {
  const a = norm(ar);
  if (!a) return false;
  if (LIB.has(a)) return true;
  const parts = a.split(/\s*(?:&|and|with|feat\.?|featuring)\s*/);
  return parts.length > 1 && parts.every(p => p && LIB.has(norm(p)));
};
const rows = [];
for (const item of $input.all()) {
  const j = item.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && j.played_at) rows.push(j);
  else if (j && Array.isArray(j.data)) rows.push(...j.data);
}
const tally = {}, artists = {};
let spins = 0;
for (const r of rows) {
  const song = r.song || {};
  const ti = String(song.title || '').trim().slice(0, 140);
  const ar = String(song.artist || '').trim().slice(0, 140);
  if (!ti || !r.played_at || !isMusic(ar)) continue;
  spins++;
  const key = (ti + '|' + ar).toLowerCase();
  const e = tally[key] || { ti, ar, n: 0 };
  e.n++; tally[key] = e;
  const ak = ar.toLowerCase();
  artists[ak] = artists[ak] || { ar, n: 0 };
  artists[ak].n++;
}
const top = Object.values(tally).sort((a, b) => b.n - a.n).slice(0, 12);
const topArtists = Object.values(artists).sort((a, b) => b.n - a.n).slice(0, 10);
const cutoff = Date.now() - 30 * 86400000;
const debuts = Object.values(sd.all)
  .filter(r => r.first && Date.parse(r.first) >= cutoff && isMusic(r.ar))
  .sort((a, b) => (a.first < b.first ? 1 : -1))
  .slice(0, 12)
  .map(r => ({ ti: r.ti, ar: r.ar, first: r.first, n: r.n }));
return [{ json: { ok: true, since: sd.since || null, window: { days: 7 }, spins, uniques: Object.keys(tally).length, top, topArtists, debuts } }];
